import { Transaction, FileModel } from '../types';
import { ContractExecutor } from './engine/ContractExecutor';
import { Fingerprinter } from './processors/Fingerprinter';
import { DateResolver } from './processors/DateResolver';
import { AmountResolver } from './processors/AmountResolver';
import { TypeResolver } from './processors/TypeResolver';
import { NameResolver } from './processors/NameResolver';
import { Logger } from '../services/monitoringService';

export interface StrategyResult {
    transactions: Transaction[];
    strategyName: string;
    status?: 'MODEL_REQUIRED';
    fileName?: string;
    fingerprint?: any;
    preview?: string;
}

export interface BankStrategy {
    name: string;
    canHandle(filename: string, content: any, models?: FileModel[]): boolean;
    parse(content: any, yearAnchor: number, models?: FileModel[], globalKeywords?: string[]): Transaction[] | Promise<Transaction[]>;
}

/**
 * 🛡️ ESTRATÉGIA DE CONTRATO (V3 - POLÍTICA RESTRITIVA)
 * Só executa se houver um modelo previamente aprendido e aprovado.
 */
export const DatabaseModelStrategy: BankStrategy = {
    name: 'Modelo Aprendido',
    canHandle: (filename, content, models) => {
        if (!models || models.length === 0) return false;
        const rawText = content?.__rawText || (typeof content === 'string' ? content : "");
        const fileFp = Fingerprinter.generate(rawText);
        if (!fileFp) return false;

        return models.some(m => 
            m.is_active && 
            (m.fingerprint.headerHash === fileFp.headerHash)
        );
    },
    parse: async (content, yearAnchor, models, globalKeywords = []) => {
        const rawText = content?.__rawText || (typeof content === 'string' ? content : "");
        const fileFp = Fingerprinter.generate(rawText);

        const model = models?.find(m => 
            m.is_active && 
            (m.fingerprint.headerHash === fileFp?.headerHash)
        );

        if (!model) return [];

        console.log(`[Strategy:CONTRACT] Aplicando padrão certificado: "${model.name}"`);
        return await ContractExecutor.apply(model, content, globalKeywords);
    }
};

/**
 * ESTRATÉGIA GENÉRICA: Reservada APENAS para dados virtuais (Gmail/API).
 * Bloqueada para arquivos físicos de upload.
 */
export const GenericStrategy: BankStrategy = {
    name: 'Genérico (Virtual)',
    canHandle: (filename, content) => {
        // Só permite se explicitamente vier de fonte virtual
        return content?.__source === 'gmail' || content?.__source === 'virtual';
    },
    parse: (content, yearAnchor, models, globalKeywords = []) => {
        const rawText = content?.__rawText || (typeof content === 'string' ? content : "");
        const lines = rawText.split(/\r?\n/).filter((l: string) => l.trim().length > 0);
        if (lines.length === 0) return [];

        const delimiter = Fingerprinter.detectDelimiter(lines[0]);
        const grid = lines.map((l: string) => l.split(delimiter));

        const dateIdx = DateResolver.identifyDateColumn(grid);
        const amountIdx = AmountResolver.identifyAmountColumn(grid, [dateIdx]);
        const nameIdx = NameResolver.identifyNameColumn(grid, [dateIdx, amountIdx]);

        const transactions: Transaction[] = [];

        grid.forEach((cols, index) => {
            const rawDate = dateIdx !== -1 ? (cols[dateIdx] || '') : '';
            const rawAmount = amountIdx !== -1 ? (cols[amountIdx] || '') : '';
            const rawDesc = nameIdx !== -1 ? (cols[nameIdx] || '') : cols.join(' ');

            const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
            const stdAmount = AmountResolver.clean(rawAmount);
            const numVal = parseFloat(stdAmount);

            if (isoDate && !isNaN(numVal)) {
                const cleaned = NameResolver.clean(rawDesc, globalKeywords);
                transactions.push({
                    id: `gen-${index}-${Date.now()}`,
                    date: isoDate,
                    description: cleaned,
                    rawDescription: cols.join('|'),
                    amount: numVal,
                    originalAmount: rawAmount,
                    cleanedDescription: cleaned,
                    contributionType: TypeResolver.resolveFromDescription(rawDesc)
                });
            }
        });
        return transactions;
    }
};

export const StrategyEngine = {
    strategies: [DatabaseModelStrategy, GenericStrategy],
    process: async (filename: string, content: any, models: FileModel[] = [], globalKeywords: string[] = [], overrideModel?: FileModel): Promise<StrategyResult> => {
        const rawText = content?.__rawText || (typeof content === 'string' ? content : "");
        const source = content?.__source || 'unknown';

        // 1. Prioridade Máxima: Override (Usado no Laboratório de Treino)
        if (overrideModel) {
            const txs = await DatabaseModelStrategy.parse(content, 2025, [overrideModel], globalKeywords);
            return { transactions: txs, strategyName: `Treino: ${overrideModel.name}` };
        }

        // 2. Busca de Modelo Certificado
        const fileFp = Fingerprinter.generate(rawText);
        const targetModel = models.find(m => m.is_active && m.fingerprint.headerHash === fileFp?.headerHash);

        if (targetModel) {
            const txs = await DatabaseModelStrategy.parse(content, 2025, [targetModel], globalKeywords);
            return { transactions: txs, strategyName: `Contrato: ${targetModel.name}` };
        }

        // 3. BARREIRA DE SEGURANÇA: Se for ARQUIVO e não deu match, BLOQUEIA e pede modelo.
        // Nunca tenta adivinhar dados de extratos bancários sem modelo.
        if (source === 'file' || source === 'ingestion_string' || source === 'unknown') {
            console.warn(`[StrategyEngine] Bloqueio de segurança: Nenhum modelo para o DNA ${fileFp?.headerHash}`);
            return { 
                status: 'MODEL_REQUIRED',
                fileName: filename,
                fingerprint: fileFp,
                preview: rawText.substring(0, 500),
                transactions: [], 
                strategyName: 'Requisitar Modelo'
            };
        }

        // 4. Fallback: Apenas para Gmail ou Fontes Virtuais
        if (source === 'gmail' || source === 'virtual') {
            const txs = GenericStrategy.parse(content, 2025, [], globalKeywords) as Transaction[];
            return { transactions: txs, strategyName: 'Genérico (Virtual)' };
        }

        return { transactions: [], strategyName: 'Inconclusivo' };
    }
};

import { Transaction, FileModel } from '../types';
import { StrategyEngine, StrategyResult } from '../core/strategies';
import { Fingerprinter } from '../core/processors/Fingerprinter';
import { IngestionOrchestrator } from '../core/engine/IngestionOrchestrator';

export * from './utils/parsingUtils';
export * from './logic/matchingLogic';
export * from './logic/filteringLogic';

export const generateFingerprint = Fingerprinter.generate;

/**
 * 🛠️ ADAPTER ESTRUTURAL (V2)
 */
function normalizeIngestionInput(input: any) {
    if (Array.isArray(input)) return input;
    if (typeof input === 'string') {
        return {
            __rawText: input,
            __source: 'file' // Força identificação como arquivo para ativar bloqueios do motor
        };
    }
    return input;
}

export const findMatchingModel = (content: string, models: FileModel[]): { model: FileModel, score: number } | null => {
    if (!models || models.length === 0) return null;
    const fileFp = Fingerprinter.generate(content);
    if (!fileFp) return null;

    // RIGOR ABSOLUTO: O match deve ser baseado no HeaderHash (DNA estrutural).
    // Não permitimos mais "score aproximado" para evitar que um banco use o modelo de outro.
    const bestMatch = models.find(m => m.is_active && m.fingerprint.headerHash === fileFp.headerHash);

    return bestMatch ? { model: bestMatch, score: 100 } : null;
};

/**
 * PROCESSADOR DE PIPELINE (V14 - SEGURANÇA E FIDELIDADE)
 */
export const processFileContent = async (
    content: string, 
    fileName: string, 
    models: FileModel[] = [], 
    globalKeywords: string[] = []
): Promise<StrategyResult & { appliedModel?: any }> => {

    const normalizedContent = IngestionOrchestrator.normalizeRawContent(content);
    const matchResult = findMatchingModel(normalizedContent, models);
    const targetModel = matchResult?.model;

    const adaptedInput = normalizeIngestionInput(normalizedContent);

    // O StrategyEngine agora decide se processa ou se pede modelo.
    const result = await StrategyEngine.process(
        fileName, 
        adaptedInput, 
        models, 
        targetModel ? [] : globalKeywords,
        targetModel
    );

    if (result.status === 'MODEL_REQUIRED') {
        return result;
    }

    const transactions = Array.isArray(result?.transactions) ? result.transactions : [];

    return {
        ...result,
        transactions,
        appliedModel: targetModel ? { id: targetModel.id, name: targetModel.name, confidenceScore: 100 } : undefined
    };
};

export const parseContributors = (content: string, ignoreKeywords: string[] = [], typeKeywords: string[] = []): any[] => {
    const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    if (lines.length < 2) return [];
    const delimiter = Fingerprinter.detectDelimiter(lines[0]);
    const rows = lines.map(l => l.split(delimiter));

    const contributors = rows.slice(1).map(row => ({
        name: row[0] || 'Desconhecido',
        amount: parseFloat(String(row[1] || '0').replace(/[R$\s]/g, '').replace(',', '.')) || 0,
        date: row[2] || ''
    })).filter(c => c.name !== 'Desconhecido');

    return contributors;
};

import { Transaction, FileModel } from '../../types';
import { Fingerprinter } from '../processors/Fingerprinter';
import { StrategyEngine } from '../strategies';

/**
 * 🎛️ INGESTION ORCHESTRATOR (V15 - NORMALIZAÇÃO UNIFICADA)
 * -------------------------------------------------------
 * Garante que a "visão" do sistema seja idêntica no Treino e na Operação.
 */
export const IngestionOrchestrator = {
    /**
     * Normalização: Mantém a integridade estrutural.
     * Preserva delimitadores para não quebrar o DNA do arquivo.
     */
    normalizeRawContent(content: string): string {
        if (!content) return "";

        return content
            .split(/\r?\n/)
            .map(line => line.trimEnd())
            // Mantém linhas que tenham conteúdo útil ou delimitadores estruturais
            .filter(l => l.trim().length > 0)
            .join('\n');
    },

    async processFile(
        file: File, 
        content: string, 
        models: FileModel[], 
        globalKeywords: string[]
    ): Promise<any> {
        // NORMALIZAÇÃO UNIFICADA
        const processedContent = this.normalizeRawContent(content);
        const fingerprint = Fingerprinter.generate(processedContent);

        console.log(`[Pipeline:INGESTION] Processando arquivo: ${file.name}`);

        const result = await StrategyEngine.process(
            file.name, 
            { __rawText: processedContent, __source: 'file' }, 
            models, 
            globalKeywords
        );

        return {
            source: 'upload',
            transactions: result.transactions || [],
            status: result.status,
            fileName: result.fileName || file.name,
            fingerprint: result.fingerprint || fingerprint || { columnCount: 0 },
            preview: result.preview || processedContent.substring(0, 500),
            strategyUsed: result.strategyName
        };
    },

    async processVirtualData(
        sourceName: string,
        transactions: Transaction[],
        globalKeywords: string[]
    ): Promise<any> {
        return {
            source: 'virtual',
            transactions: transactions,
            strategyUsed: `Virtual:${sourceName}`,
            fingerprint: { columnCount: 3 }
        };
    }
};

