import { Transaction, FileModel } from '../../types';
import { DateResolver } from '../processors/DateResolver';
import { AmountResolver } from '../processors/AmountResolver';
import { NameResolver } from '../processors/NameResolver';
import { TypeResolver } from '../processors/TypeResolver';
import { extractTransactionsWithModel } from '../../services/geminiService';

/**
 * 📜 CONTRACT EXECUTOR (V27 - OTIMIZAÇÃO PARA ALTA PERFORMANCE)
 * --------------------------------------------------------------------------
 * Ajustado para evitar erros 429 do Google Gemini através de fatias maiores.
 */

export const ContractExecutor = {
    /**
     * Aplica as coordenadas do contrato ao conteúdo bruto.
     */
    async apply(model: FileModel, adaptedInput: any, globalKeywords: string[] = []): Promise<Transaction[]> {
        if (!model || !model.mapping) return [];

        const rawText = adaptedInput?.__rawText || (typeof adaptedInput === 'string' ? adaptedInput : "");
        if (!rawText.trim()) return [];

        // 🧠 EXECUÇÃO COGNITIVA COM FATIAMENTO OTIMIZADO (MODO BLOCO)
        if (model.mapping.extractionMode === 'BLOCK') {
            console.log(`[Executor:BLOCK] Aplicando Inteligência de Bloco para: "${model.name}"`);

            const snippet = model.snippet || "";
            const trainingContext = `EXEMPLOS DE TREINO:\n${snippet.substring(0, 2000)}`;

            // Divide o texto em linhas
            const lines = rawText.split(/\r?\n/).filter(l => l.trim().length > 0);

            // OTIMIZAÇÃO: Gemini 3 tem janela gigante. Usar fatias de 40k chars reduz requisições drasticamente (Adeus 429)
            const CHUNK_CHAR_LIMIT = 40000; 

            let currentChunkLines: string[] = [];
            let currentChunkSize = 0;
            const chunks: string[] = [];

            for (const line of lines) {
                if (currentChunkSize + line.length > CHUNK_CHAR_LIMIT && currentChunkLines.length > 0) {
                    chunks.push(currentChunkLines.join('\n'));
                    currentChunkLines = [];
                    currentChunkSize = 0;
                }
                currentChunkLines.push(line);
                currentChunkSize += line.length;
            }
            if (currentChunkLines.length > 0) {
                chunks.push(currentChunkLines.join('\n'));
            }

            console.log(`[Executor:BLOCK] Processando ${chunks.length} fatia(s). Evitando 429.`);

            const allResults: Transaction[] = [];

            for (let i = 0; i < chunks.length; i++) {
                // Pequena pausa entre fatias se houver mais de uma, para respeitar RPM (Requests Per Minute)
                if (i > 0) await new Promise(r => setTimeout(r, 1500));

                console.log(`[Executor:BLOCK] Processando fatia ${i + 1}/${chunks.length}...`);
                const aiResult = await extractTransactionsWithModel(chunks[i], trainingContext);

                if (aiResult && aiResult.length > 0) {
                    const mapped = aiResult.map((tx: any, idx: number) => {
                        const originalDesc = tx.description?.trim();
                        return {
                            id: `exec-blk-${model.id}-${i}-${idx}-${Date.now()}`,
                            date: tx.date,
                            description: originalDesc,
                            rawDescription: tx.description,
                            amount: tx.amount,
                            originalAmount: String(tx.amount),
                            cleanedDescription: originalDesc,
                            contributionType: tx.type || 'AUTO',
                            paymentMethod: tx.paymentMethod || 'OUTROS'
                        };
                    });
                    allResults.push(...mapped);
                }
            }

            console.log(`[Executor:BLOCK] Concluído! Total: ${allResults.length} registros.`);
            return allResults;
        }

        // 🚀 EXECUÇÃO DETERMINÍSTICA (MODO COLUNAS CLÁSSICO)
        // Instantâneo e imune a erros de IA
        const lines = rawText.split(/\r?\n/).filter(l => l.trim().length > 0);
        const { mapping } = model;
        const yearAnchor = DateResolver.discoverAnchorYear(rawText);
        const results: Transaction[] = [];

        lines.forEach((line, idx) => {
            if (idx < (mapping.skipRowsStart || 0)) return;

            const cells = line.split(';'); 
            const rawDate = cells[mapping.dateColumnIndex] || "";
            const rawDesc = cells[mapping.descriptionColumnIndex] || "";
            const rawAmount = cells[mapping.amountColumnIndex] || "";

            if (!rawDate && !rawDesc && !rawAmount) return;

            const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
            const stdAmount = AmountResolver.clean(rawAmount);
            const numAmount = parseFloat(stdAmount);

            if (isoDate && !isNaN(numAmount)) {
                const finalDesc = rawDesc.trim();
                results.push({
                    id: `exec-col-${model.id}-${idx}-${Date.now()}`,
                    date: isoDate,
                    description: finalDesc,
                    rawDescription: line,
                    amount: numAmount,
                    originalAmount: rawAmount,
                    cleanedDescription: finalDesc, 
                    contributionType: TypeResolver.resolveFromDescription(rawDesc),
                    paymentMethod: mapping.paymentMethodColumnIndex !== undefined && cells[mapping.paymentMethodColumnIndex] 
                        ? cells[mapping.paymentMethodColumnIndex] 
                        : 'OUTROS'
                });
            }
        });

        console.log(`[Executor:COLUMNS] Extração instantânea concluída: ${results.length} registros.`);
        return results;
    }
};

import { CanonicalDocumentNormalizer } from './CanonicalDocumentNormalizer';

/**
 * SERVIÇO DE DOMÍNIO: FINGERPRINTER (V7 - DNA ULTRA-ROBUSTO)
 * --------------------------------------------------------------------------
 * Gera a identidade estrutural definitiva ignorando ruídos de delimitadores.
 */

export interface StructuralFingerprint {
    columnCount: number;
    delimiter: string;
    headerHash: string | null;
    dataTopology: string;
    canonicalSignature?: string;
    structuralPattern?: string;
}

export const Fingerprinter = {
    detectDelimiter: (line: string): string => {
        if (!line) return ';';
        const candidates = [';', ',', '\t', '|'];
        const counts = candidates.map(char => ({ 
            char, 
            count: line.split(char).length - 1 
        }));
        counts.sort((a, b) => b.count - a.count);
        return counts[0].count > 0 ? counts[0].char : ';';
    },

    /**
     * Gera o DNA estrutural blindado. 
     * Ignora delimitadores na geração do Hash para garantir paridade PDF/Excel.
     */
    generate: (content: string): StructuralFingerprint | null => {
        if (!content || typeof content !== 'string') return null;

        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length === 0) return null;

        // Pega a primeira linha e limpa colunas vazias à direita (comum no Excel)
        const rawHeader = lines[0];
        const delimiter = Fingerprinter.detectDelimiter(rawHeader);

        // Remove delimitadores extras do final da linha que o Excel gera
        const cleanLine = rawHeader.replace(new RegExp(`[${delimiter} ]+$`), '');
        const cells = cleanLine.split(delimiter);

        // 🛡️ HASH SEMANTICAMENTE PURO:
        // Remove TUDO que não é letra ou número para gerar o Hash.
        // Isso garante que "Data;Desc;Valor" e "Data , Desc , Valor ; ;" gerem o MESMO HASH.
        const hashBase = cleanLine
            .normalize('NFD')
            .replace(/[\u0300-\u036f]/g, '') 
            .replace(/[^A-Z0-9]/gi, '') 
            .toUpperCase();

        let hash = 5381;
        for (let i = 0; i < hashBase.length; i++) {
            hash = ((hash << 5) + hash) + hashBase.charCodeAt(i);
        }
        const headerHash = Math.abs(hash).toString(36);

        const structuralPattern = CanonicalDocumentNormalizer.generateStructuralPattern(lines);

        return { 
            columnCount: cells.length, 
            delimiter, 
            headerHash, 
            dataTopology: 'FIXED_CONTRACT',
            structuralPattern
        };
    }
};

import { Transaction, FileModel } from '../../types';
