import { Transaction, FileModel } from '../../types';
import { DateResolver } from '../processors/DateResolver';
import { AmountResolver } from '../processors/AmountResolver';
import { NameResolver } from '../processors/NameResolver';
import { TypeResolver } from '../processors/TypeResolver';
import { extractTransactionsWithModel } from '../../services/geminiService';

/**
 * 📜 CONTRACT EXECUTOR (V28 - FIDELIDADE TOTAL)
 * --------------------------------------------------------------------------
 * Segue o contrato do modelo sem normalizações extras.
 */

export const ContractExecutor = {
    /**
     * Aplica as coordenadas do contrato ao conteúdo bruto.
     */
    async apply(model: FileModel, adaptedInput: any, globalKeywords: string[] = []): Promise<Transaction[]> {
        if (!model || !model.mapping) return [];

        const rawText = adaptedInput?.__rawText || (typeof adaptedInput === 'string' ? adaptedInput : "");
        if (!rawText.trim()) return [];

        // 🧠 MODO BLOCO (IA)
        if (model.mapping.extractionMode === 'BLOCK') {
            const snippet = model.snippet || "";
            const trainingContext = `EXEMPLOS DE TREINO:\n${snippet.substring(0, 2000)}`;
            const lines = rawText.split(/\r?\n/).filter(l => l.trim().length > 0);
            const CHUNK_CHAR_LIMIT = 40000; 

            let currentChunkLines: string[] = [];
            let currentChunkSize = 0;
            const chunks: string[] = [];

            for (const line of lines) {
                if (currentChunkSize + line.length > CHUNK_CHAR_LIMIT && currentChunkLines.length > 0) {
                    chunks.push(currentChunkLines.join('\n'));
                    currentChunkLines = [];
                    currentChunkSize = 0;
                }
                currentChunkLines.push(line);
                currentChunkSize += line.length;
            }
            if (currentChunkLines.length > 0) chunks.push(currentChunkLines.join('\n'));

            const allResults: Transaction[] = [];
            for (let i = 0; i < chunks.length; i++) {
                if (i > 0) await new Promise(r => setTimeout(r, 1500));
                const aiResult = await extractTransactionsWithModel(chunks[i], trainingContext);
                if (aiResult && aiResult.length > 0) {
                    const mapped = aiResult.map((tx: any, idx: number) => ({
                        id: `exec-blk-${model.id}-${i}-${idx}-${Date.now()}`,
                        date: tx.date,
                        description: tx.description?.trim(),
                        rawDescription: tx.description,
                        amount: tx.amount,
                        originalAmount: String(tx.amount),
                        cleanedDescription: tx.description?.trim(),
                        contributionType: tx.type || 'AUTO',
                        paymentMethod: tx.paymentMethod || 'OUTROS'
                    }));
                    allResults.push(...mapped);
                }
            }
            return allResults;
        }

        // 🚀 MODO COLUNAS (DETERMINÍSTICO)
        const lines = rawText.split(/\r?\n/);
        const { mapping } = model;
        const results: Transaction[] = [];

        // Para colunas, usamos um ano base se a data for parcial, 
        // mas não tentamos "descobrir" o ano no texto para não fugir do contrato.
        const currentYear = new Date().getFullYear();

        lines.forEach((line, idx) => {
            if (idx < (mapping.skipRowsStart || 0)) return;

            const cells = line.split(';'); 
            const rawDate = cells[mapping.dateColumnIndex] || "";
            const rawDesc = cells[mapping.descriptionColumnIndex] || "";
            const rawAmount = cells[mapping.amountColumnIndex] || "";

            if (!rawDate && !rawDesc && !rawAmount) return;

            // Conversão técnica (Mínima necessária para o sistema funcionar)
            const isoDate = DateResolver.resolveToISO(rawDate, currentYear);
            const stdAmount = AmountResolver.clean(rawAmount);
            const numAmount = parseFloat(stdAmount);

            if (isoDate && !isNaN(numAmount)) {
                const finalDesc = rawDesc.trim();
                results.push({
                    id: `exec-col-${model.id}-${idx}-${Date.now()}`,
                    date: isoDate,
                    description: finalDesc,
                    rawDescription: line,
                    amount: numAmount,
                    originalAmount: rawAmount,
                    cleanedDescription: finalDesc, 
                    contributionType: TypeResolver.resolveFromDescription(rawDesc),
                    paymentMethod: mapping.paymentMethodColumnIndex !== undefined && cells[mapping.paymentMethodColumnIndex] 
                        ? cells[mapping.paymentMethodColumnIndex] 
                        : 'OUTROS'
                });
            }
        });

        console.log(`[Executor:COLUMNS] Extração direta concluída: ${results.length} registros.`);
        return results;
    }
};

import { supabase } from './supabaseClient';
import { FileModel } from '../types';
import { Logger } from './monitoringService';
import { get, set, del } from 'idb-keyval';

const PERSISTENT_STORAGE_KEY = 'identificapix-models-storage-v12';

export const modelService = {
    /**
     * Recupera os modelos do usuário.
     * V12: Sincronia total com o servidor para eliminar modelos excluídos (ghosts).
     */
    getUserModels: async (userId: string): Promise<FileModel[]> => {
        try {
            // 1. Busca a verdade absoluta no servidor
            const { data, error } = await supabase
                .from('file_models')
                .select('*')
                .eq('is_active', true)
                .eq('user_id', userId);

            if (error) throw error;

            const mapDbRowToModel = (row: any): FileModel => ({
                id: row.id,
                name: row.name,
                user_id: row.user_id,
                version: row.version || 1,
                lineage_id: row.lineage_id || row.id,
                is_active: row.is_active,
                status: row.status || 'draft',
                fingerprint: typeof row.fingerprint === 'string' ? JSON.parse(row.fingerprint) : row.fingerprint,
                mapping: typeof row.mapping === 'string' ? JSON.parse(row.mapping) : row.mapping,
                parsingRules: row.parsing_rules ? (typeof row.parsing_rules === 'string' ? JSON.parse(row.parsing_rules) : row.parsing_rules) : { ignoredKeywords: [], rowFilters: [] },
                snippet: row.snippet,
                createdAt: row.created_at || new Date().toISOString(),
                lastUsedAt: row.last_used_at
            });

            const remoteModels = data ? data.map(mapDbRowToModel) : [];

            // 2. Sobrescreve o cache local com a lista limpa do servidor
            await set(PERSISTENT_STORAGE_KEY, remoteModels);

            console.log(`[ModelService] Sincronizado: ${remoteModels.length} modelos ativos encontrados.`);
            return remoteModels;

        } catch (e) {
            console.warn("[ModelService] Falha na rede, tentando ler cache local...", e);
            const cached = await get(PERSISTENT_STORAGE_KEY);
            return Array.isArray(cached) ? cached : [];
        }
    },

    saveModel: async (model: Omit<FileModel, 'id' | 'createdAt'>): Promise<FileModel | null> => {
        try {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error("Sessão expirada.");

            // Desativa versões anteriores da mesma linhagem
            if (model.lineage_id) {
                await supabase.from('file_models')
                    .update({ is_active: false })
                    .eq('lineage_id', model.lineage_id);
            }

            const { data, error } = await supabase
                .from('file_models')
                .insert([{
                    name: model.name,
                    user_id: session.user.id,
                    version: model.version || 1,
                    lineage_id: model.lineage_id,
                    is_active: true,
                    status: model.status || 'approved',
                    fingerprint: model.fingerprint,
                    mapping: model.mapping,
                    parsing_rules: model.parsingRules,
                    snippet: model.snippet
                }])
                .select('*')
                .single();

            if (error) throw error;

            // Invalida cache local para forçar refresh na próxima leitura
            await del(PERSISTENT_STORAGE_KEY);

            return data;
        } catch (error) {
            Logger.error("Erro ao salvar modelo", error);
            throw error;
        }
    },

    deleteModel: async (id: string) => {
        const { error } = await supabase.from('file_models').delete().eq('id', id);
        if (!error) {
            await del(PERSISTENT_STORAGE_KEY); // Limpa cache
            return true;
        }
        return false;
    },

    getAllModelsAdmin: async (): Promise<FileModel[]> => {
        const { data, error } = await supabase.from('file_models').select('*').order('created_at', { ascending: false });
        if (error) return [];
        return data as any[];
    },

    updateModelName: async (id: string, name: string) => {
        const { error } = await supabase.from('file_models').update({ name }).eq('id', id);
        if (!error) {
            await del(PERSISTENT_STORAGE_KEY);
            return true;
        }
        return false;
    }
};

import { Transaction, FileModel } from '../types';
import { ContractExecutor } from './engine/ContractExecutor';
import { Fingerprinter } from './processors/Fingerprinter';
import { DateResolver } from './processors/DateResolver';
import { AmountResolver } from './processors/AmountResolver';
import { NameResolver } from './processors/NameResolver';

export interface StrategyResult {
    transactions: Transaction[];
    strategyName: string;
    status?: 'MODEL_REQUIRED';
    fileName?: string;
    fingerprint?: any;
    preview?: string;
}

export interface BankStrategy {
    name: string;
    canHandle(filename: string, content: any, models?: FileModel[]): boolean;
    parse(content: any, models?: FileModel[], globalKeywords?: string[]): Transaction[] | Promise<Transaction[]>;
}

export const DatabaseModelStrategy: BankStrategy = {
    name: 'Modelo Aprendido',
    canHandle: (filename, content, models) => {
        if (!models || models.length === 0) return false;
        const rawText = content?.__rawText || (typeof content === 'string' ? content : "");
        const fileFp = Fingerprinter.generate(rawText);
        if (!fileFp) return false;

        return models.some(m => 
            m.is_active && 
            m.fingerprint.headerHash === fileFp.headerHash &&
            m.fingerprint.columnCount === fileFp.columnCount
        );
    },
    parse: async (content, models, globalKeywords = []) => {
        const rawText = content?.__rawText || (typeof content === 'string' ? content : "");
        const fileFp = Fingerprinter.generate(rawText);

        const model = models?.find(m => 
            m.is_active && 
            m.fingerprint.headerHash === fileFp?.headerHash &&
            m.fingerprint.columnCount === fileFp?.columnCount
        );

        if (!model) return [];

        console.log(`[StrategyEngine] 🎯 Aplicando Modelo: "${model.name}" (v${model.version}) | DNA: ${model.fingerprint.headerHash}`);
        return await ContractExecutor.apply(model, content, globalKeywords);
    }
};

export const StrategyEngine = {
    process: async (filename: string, content: any, models: FileModel[] = [], globalKeywords: string[] = [], overrideModel?: FileModel): Promise<StrategyResult> => {
        const rawText = content?.__rawText || (typeof content === 'string' ? content : "");
        const source = content?.__source || 'unknown';

        if (overrideModel) {
            const txs = await DatabaseModelStrategy.parse(content, [overrideModel], globalKeywords);
            return { transactions: txs, strategyName: `Treino: ${overrideModel.name}` };
        }

        const fileFp = Fingerprinter.generate(rawText);
        const targetModel = models.find(m => 
            m.is_active && 
            m.fingerprint.headerHash === fileFp?.headerHash &&
            m.fingerprint.columnCount === fileFp?.columnCount
        );

        if (targetModel) {
            const txs = await DatabaseModelStrategy.parse(content, [targetModel], globalKeywords);
            return { transactions: txs, strategyName: `Contrato: ${targetModel.name}` };
        }

        if (source === 'file' || source === 'unknown') {
            console.warn(`[StrategyEngine] ⚠️ Bloqueio: Nenhum modelo compatível para DNA ${fileFp?.headerHash}`);
            return { 
                status: 'MODEL_REQUIRED',
                fileName: filename,
                fingerprint: fileFp,
                preview: rawText.substring(0, 500),
                transactions: [], 
                strategyName: 'Requisitar Modelo'
            };
        }

        return { transactions: [], strategyName: 'Inconclusivo' };
    }
};

