/**
 * 🎯 FONTE ÚNICA DE VERDADE: INTELIGÊNCIA NOMINAL (V4 - ULTRA CLEAN)
 * Centraliza toda a lógica de sanitização de nomes e descrições.
 */
export class NameResolver {

  static identifyNameColumn(rows: string[][], excludedIndices: number[] = []): number {
    const sample = rows.slice(0, 50);
    if (sample.length === 0) return -1;
    const scores = new Array(rows[0]?.length || 0).fill(0);
    sample.forEach(row => {
        row.forEach((cell, index) => {
            if (excludedIndices.includes(index)) return;
            const val = String(cell || '').trim();
            if (val.length > 4 && !/^[\d.,R$\s\-()]+$/.test(val)) {
                scores[index] += 1;
                if (val.split(' ').length > 1) scores[index] += 0.5;
            }
        });
    });
    const maxScore = Math.max(...scores);
    return maxScore > 0 ? scores.indexOf(maxScore) : -1;
  }

  /**
   * LIMPEZA (DESATIVADA): Retorna o texto original conforme solicitado pelo usuário.
   */
  static clean(rawName: string, userKeywords: string[] = []): string {
    if (!rawName) return '';
    return rawName.trim();
  }

  /**
   * FORMATAÇÃO VISUAL (WYSIWYG): Remove ruídos de extrato para exibição.
   * Remove "RECEBIMENTO PIX", "PAGAMENTO", "TED", "DOC" e sequências de números (IDs/CPF).
   */
  static formatDisplayName(name: string): string {
    if (!name) return '';

    return name
      // 1. Remove padrões comuns de extrato bancário
      .replace(/\b(RECEBIMENTO|PAGAMENTO|TRANSF[.]?|TRANSFERENCIA|PIX|TED|DOC|CREDITO|DEBITO)\b/gi, '')
      // 2. Remove sequências longas de números (CPF/CNPJ/IDs) - 8 ou mais dígitos
      .replace(/\b\d{8,}\b/g, '')
      // 3. Remove asteriscos e caracteres de preenchimento
      .replace(/\*+[\d.Xx-]*\*+/g, '')
      // 4. Remove fragmentos isolados de 1-2 caracteres que sobram da limpeza
      .replace(/\b[A-Z]{1,2}\b/g, (match) => {
          // Mantém se parecer parte de um nome (Ex: 'de', 'da', 'do')
          const lower = match.toLowerCase();
          return ['de', 'da', 'do', 'e', 'o'].includes(lower) ? match : '';
      })
      // 5. Colapsa espaços múltiplos e limpa pontas
      .replace(/\s+/g, ' ')
      .trim()
      .toUpperCase();
  }

  /**
   * NORMALIZAÇÃO: Usada apenas para MATCHING interno.
   */
  static normalize(text: string): string {
    if (!text) return '';
    return text
      .toUpperCase()
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '') 
      .replace(/\s+/g, ' ')           
      .trim();
  }
}

import { Transaction, FileModel } from '../../types';
import { DateResolver } from '../processors/DateResolver';
import { AmountResolver } from '../processors/AmountResolver';
import { TypeResolver } from '../processors/TypeResolver';
import { NameResolver } from '../processors/NameResolver';
import { extractTransactionsWithModel } from '../../services/geminiService';

/**
 * 📜 CONTRACT EXECUTOR (V31 - PARIDADE TOTAL)
 */
export const ContractExecutor = {
    async apply(model: FileModel, adaptedInput: any, globalKeywords: string[] = []): Promise<Transaction[]> {
        if (!model || !model.mapping) return [];

        const rawText = adaptedInput?.__rawText || (typeof adaptedInput === 'string' ? adaptedInput : "");
        if (!rawText.trim()) return [];

        // 🧠 MODO BLOCO (IA) - Usado para layouts onde as colunas variam
        if (model.mapping.extractionMode === 'BLOCK') {
            console.log(`[Executor:BLOCK] Iniciando extração via IA para: "${model.name}"`);

            // Contexto rico para a IA replicar o aprendizado do Laboratório
            const snippet = model.snippet || "";
            const trainingContext = `### EXEMPLOS DE TREINO (GABARITO):\n${snippet.substring(0, 3000)}\n\nSiga RIGOROSAMENTE o padrão de limpeza acima.`;

            const lines = rawText.split(/\r?\n/).filter(l => l.trim().length > 0);
            const CHUNK_CHAR_LIMIT = 35000; 

            let currentChunkLines: string[] = [];
            let currentChunkSize = 0;
            const chunks: string[] = [];

            for (const line of lines) {
                if (currentChunkSize + line.length > CHUNK_CHAR_LIMIT && currentChunkLines.length > 0) {
                    chunks.push(currentChunkLines.join('\n'));
                    currentChunkLines = [];
                    currentChunkSize = 0;
                }
                currentChunkLines.push(line);
                currentChunkSize += line.length;
            }
            if (currentChunkLines.length > 0) chunks.push(currentChunkLines.join('\n'));

            console.log(`[Executor:BLOCK] Processando ${chunks.length} fatias via Gemini...`);

            const allResults: Transaction[] = [];
            for (let i = 0; i < chunks.length; i++) {
                if (i > 0) await new Promise(r => setTimeout(r, 1200));
                const aiResult = await extractTransactionsWithModel(chunks[i], trainingContext);
                if (aiResult && aiResult.length > 0) {
                    const mapped = aiResult.map((tx: any, idx: number) => {
                        const cleanDesc = NameResolver.formatDisplayName(tx.description);
                        return {
                            id: `exec-blk-${model.id}-${i}-${idx}-${Date.now()}`,
                            date: tx.date,
                            description: cleanDesc,
                            rawDescription: tx.description,
                            amount: tx.amount,
                            originalAmount: String(tx.amount),
                            cleanedDescription: cleanDesc,
                            contributionType: tx.type || 'AUTO',
                            paymentMethod: tx.paymentMethod || 'OUTROS'
                        };
                    });
                    allResults.push(...mapped);
                }
            }
            return allResults;
        }

        // 🚀 MODO COLUNAS (INSTANTÂNEO) - Determinístico e 100% fiel
        console.log(`[Executor:COLUMNS] Extração Direta para: "${model.name}"`);
        const lines = rawText.split(/\r?\n/);
        const { mapping } = model;
        const results: Transaction[] = [];
        const currentYear = new Date().getFullYear();

        lines.forEach((line, idx) => {
            if (idx < (mapping.skipRowsStart || 0)) return;

            const cells = line.split(';'); 
            const rawDate = cells[mapping.dateColumnIndex] || "";
            const rawDesc = cells[mapping.descriptionColumnIndex] || "";
            const rawAmount = cells[mapping.amountColumnIndex] || "";

            if (!rawDate && !rawDesc && !rawAmount) return;

            const isoDate = DateResolver.resolveToISO(rawDate, currentYear);
            const stdAmount = AmountResolver.clean(rawAmount);
            const numAmount = parseFloat(stdAmount);

            if (isoDate && !isNaN(numAmount)) {
                // APLICA LIMPEZA VISUAL IGUAL AO PDF
                const cleanDesc = NameResolver.formatDisplayName(rawDesc);

                results.push({
                    id: `exec-col-${model.id}-${idx}-${Date.now()}`,
                    date: isoDate,
                    description: cleanDesc,
                    rawDescription: line,
                    amount: numAmount,
                    originalAmount: rawAmount,
                    cleanedDescription: cleanDesc, 
                    contributionType: TypeResolver.resolveFromDescription(rawDesc),
                    paymentMethod: mapping.paymentMethodColumnIndex !== undefined && cells[mapping.paymentMethodColumnIndex] 
                        ? cells[mapping.paymentMethodColumnIndex] 
                        : 'OUTROS'
                });
            }
        });

        console.log(`[Executor:COLUMNS] Concluído! ${results.length} registros extraídos.`);
        return results;
    }
};

import { useState, useCallback, useEffect, useRef } from 'react';
import { Transaction } from '../types';
import { DateResolver } from '../core/processors/DateResolver';
import { AmountResolver } from '../core/processors/AmountResolver';
import { TypeResolver } from '../core/processors/TypeResolver';
import { NameResolver } from '../core/processors/NameResolver';

interface SafeTransaction extends Transaction {
    sourceIndex?: number;
    isValid?: boolean;
    status?: 'valid' | 'error' | 'edited' | 'ignored' | 'pending';
}

interface UseSimulationProps {
    gridData: string[][];
    activeMapping: any;
    cleaningKeywords: string[];
}

export const useSimulation = ({ gridData, activeMapping, cleaningKeywords }: UseSimulationProps) => {
    const [processedTransactions, setProcessedTransactions] = useState<SafeTransaction[]>([]);
    const [editingRowIndex, setEditingRowIndex] = useState<number | null>(null);
    const [editingRowData, setEditingRowData] = useState<SafeTransaction | null>(null);
    const [isSimulating, setIsSimulating] = useState(false);

    const lastDataRef = useRef<string>('');
    const lastMappingRef = useRef<string>('');

    const runSimulation = useCallback(() => {
        if (!gridData || gridData.length === 0) {
            setProcessedTransactions([]);
            return;
        }

        const mapping = activeMapping || { extractionMode: 'COLUMNS' };
        const isManualMappingComplete = mapping.dateColumnIndex >= 0 && mapping.amountColumnIndex >= 0;

        // MODO BLOCO INICIAL
        if (mapping.extractionMode === 'BLOCK' && !isManualMappingComplete) {
            const initialPreview = gridData.slice(0, 100).map((row, i) => {
                const rawDesc = row.join(' ');
                const cleanDesc = NameResolver.formatDisplayName(rawDesc);
                return {
                    id: `raw-${i}-${Date.now()}`,
                    date: "---",
                    description: cleanDesc || rawDesc.substring(0, 150),
                    rawDescription: row.join(';'),
                    amount: 0,
                    originalAmount: "0.00",
                    isValid: false,
                    status: 'pending' as const,
                    sourceIndex: i
                };
            });
            setProcessedTransactions(initialPreview);
            setIsSimulating(false);
        } 
        // MODO ESTRUTURADO
        else {
            setIsSimulating(true);
            const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, paymentMethodColumnIndex, skipRowsStart } = mapping;
            const newTransactions: SafeTransaction[] = [];
            const yearAnchor = DateResolver.discoverAnchorYear(gridData);

            gridData.forEach((cols, index) => {
                const isSkipped = index < (skipRowsStart || 0);
                const rawDate = dateColumnIndex >= 0 ? (cols[dateColumnIndex] || '') : '';
                const rawDesc = descriptionColumnIndex >= 0 ? (cols[descriptionColumnIndex] || '') : '';
                const rawAmount = amountColumnIndex >= 0 ? (cols[amountColumnIndex] || '') : '';

                if (!rawDate && !rawDesc && !rawAmount) return;

                const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
                const amountStr = AmountResolver.clean(rawAmount);
                const amountValue = parseFloat(amountStr);

                // APLICA LIMPEZA IDENTICA AO MOTOR REAL
                const cleanDesc = NameResolver.formatDisplayName(rawDesc);

                newTransactions.push({ 
                    id: `sim-${index}-${Date.now()}`,
                    date: isoDate || rawDate || "---", 
                    description: cleanDesc || rawDesc, 
                    rawDescription: rawDesc || "---", 
                    paymentMethod: (paymentMethodColumnIndex !== undefined && paymentMethodColumnIndex >= 0 && cols[paymentMethodColumnIndex]) ? cols[paymentMethodColumnIndex] : TypeResolver.resolveFromDescription(rawDesc),
                    amount: isNaN(amountValue) ? 0 : amountValue, 
                    originalAmount: rawAmount, 
                    cleanedDescription: cleanDesc, 
                    contributionType: 'AUTO', 
                    sourceIndex: index, 
                    isValid: !!isoDate && !isNaN(amountValue), 
                    status: isSkipped ? 'ignored' : 'valid'
                });
            });
            setProcessedTransactions(newTransactions);
            setIsSimulating(false);
        }
    }, [gridData, activeMapping]);

    useEffect(() => {
        const dataHash = gridData.length > 0 ? `${gridData.length}-${gridData[0].join('|').substring(0, 50)}` : 'empty';
        const mappingKey = JSON.stringify(activeMapping);
        if (dataHash !== lastDataRef.current || mappingKey !== lastMappingRef.current) {
            lastDataRef.current = dataHash;
            lastMappingRef.current = mappingKey;
            runSimulation();
        }
    }, [gridData, activeMapping, runSimulation]);

    return {
        processedTransactions,
        isSimulating,
        runSimulation,
        editingRowIndex,
        editingRowData,
        setEditingRowData,
        startEdit: (tx: any, idx: number) => { 
            setEditingRowIndex(idx); 
            setEditingRowData({ ...tx }); 
        },
        saveRow: (onLearned?: (raw: string[], corrected: any) => void) => {
            if (editingRowIndex !== null && editingRowData) {
                const updatedTx = { ...editingRowData, status: 'edited' as const, isValid: true };

                if (onLearned) {
                    const rawLines = (updatedTx as any).sourceRawSnippet || 
                                     (updatedTx.sourceIndex !== undefined ? gridData[updatedTx.sourceIndex] : []);
                    onLearned(rawLines, updatedTx);
                }

                setProcessedTransactions(prev => { 
                    const n = [...prev]; 
                    n[editingRowIndex] = updatedTx; 
                    return n; 
                });
                setEditingRowIndex(null);
            }
        },
        cancelEdit: () => setEditingRowIndex(null)
    };
};

import React, { useState, useEffect } from 'react';
import { PlayCircleIcon, SparklesIcon, TableCellsIcon, DocumentDuplicateIcon, BoltIcon } from '../../Icons';
import { inferMappingFromSample } from '../../../services/geminiService';
import { useUI } from '../../../contexts/UIContext';

interface MappingControlsProps {
    mapping: any;
    setMapping: (mapping: any) => void;
    columnCount: number;
    onSimulate: () => void;
    gridData: string[][];
}

export const MappingControls: React.FC<MappingControlsProps> = ({
    mapping,
    setMapping,
    columnCount,
    onSimulate,
    gridData
}) => {
    const [isAiLoading, setIsAiLoading] = useState(false);
    const { showToast } = useUI();

    if (!mapping) return null;

    const setExtractionMode = (mode: 'COLUMNS' | 'BLOCK') => {
        setMapping({ ...mapping, extractionMode: mode });
        showToast(`Modo: ${mode === 'BLOCK' ? 'Inteligência de Bloco (IA)' : 'Colunas Fixas (Instantâneo)'}`, "success");
    };

    const updateField = (field: string, value: string) => {
        const val = value === "" ? -1 : parseInt(value);
        setMapping({ ...mapping, [field]: val });
    };

    const handleAiSuggest = async () => {
        if (!gridData || gridData.length === 0) return;
        setIsAiLoading(true);
        try {
            const sample = gridData.slice(0, 30).map(row => row.join(' ')).join('\n');
            const suggestion = await inferMappingFromSample(sample);
            if (suggestion) {
                // Inteligência: Se detectamos colunas em um arquivo estruturado, 
                // preferimos COLUMNS para velocidade e precisão.
                const preferredMode = suggestion.extractionMode === 'BLOCK' && columnCount > 2 ? 'COLUMNS' : suggestion.extractionMode;

                setMapping({
                    ...mapping,
                    extractionMode: preferredMode || 'COLUMNS',
                    dateColumnIndex: suggestion.dateColumnIndex ?? -1,
                    descriptionColumnIndex: suggestion.descriptionColumnIndex ?? -1,
                    amountColumnIndex: suggestion.amountColumnIndex ?? -1,
                    paymentMethodColumnIndex: suggestion.paymentMethodColumnIndex ?? -1,
                    skipRowsStart: suggestion.skipRowsStart ?? 0
                });
                showToast(`IA detectou estrutura de ${preferredMode === 'COLUMNS' ? 'Colunas (Rápido)' : 'Bloco'}.`, "success");
            }
        } catch (e: any) {
            showToast("Falha na análise estrutural.", "error");
        } finally {
            setIsAiLoading(false);
        }
    };

    return (
        <div className="flex flex-wrap gap-4 items-center flex-1">
            <div className="flex bg-slate-200 dark:bg-slate-800 p-1 rounded-xl border border-slate-300 dark:border-slate-700">
                <button 
                    onClick={() => setExtractionMode('COLUMNS')}
                    className={`px-3 py-1.5 rounded-lg text-[10px] font-black uppercase flex items-center gap-1.5 transition-all ${mapping.extractionMode !== 'BLOCK' ? 'bg-white dark:bg-slate-700 text-indigo-600 shadow-sm' : 'text-slate-500'}`}
                    title="Modo Determinístico (Recomendado para Excel)"
                >
                    <BoltIcon className="w-3 h-3" /> COLUNAS
                </button>
                <button 
                    onClick={() => setExtractionMode('BLOCK')}
                    className={`px-3 py-1.5 rounded-lg text-[10px] font-black uppercase flex items-center gap-1.5 transition-all ${mapping.extractionMode === 'BLOCK' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500'}`}
                    title="Modo Inteligência Artificial (Mais lento)"
                >
                    <SparklesIcon className="w-3 h-3" /> BLOCO (IA)
                </button>
            </div>

            {mapping.extractionMode !== 'BLOCK' ? (
                <div className="flex gap-2 p-2 bg-slate-100 dark:bg-slate-800/50 rounded-xl border border-slate-200 dark:border-slate-700 animate-fade-in">
                    <ManualInput label="Data" field="dateColumnIndex" value={mapping.dateColumnIndex} color="text-blue-500" update={updateField} />
                    <ManualInput label="Descrição" field="descriptionColumnIndex" value={mapping.descriptionColumnIndex} color="text-purple-500" update={updateField} />
                    <ManualInput label="Valor" field="amountColumnIndex" value={mapping.amountColumnIndex} color="text-emerald-500" update={updateField} />
                </div>
            ) : (
                <div className="px-4 py-2 bg-indigo-50 dark:bg-indigo-900/20 border border-indigo-100 dark:border-indigo-800 rounded-xl animate-fade-in">
                    <p className="text-[10px] font-bold text-indigo-600 dark:text-indigo-400 uppercase leading-none">Modo Inteligência de Bloco</p>
                    <p className="text-[9px] text-slate-500 mt-1">Ideal para PDFs onde os dados não seguem colunas fixas.</p>
                </div>
            )}

            <div className="flex gap-2 ml-auto">
                <button onClick={handleAiSuggest} disabled={isAiLoading} className="flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-bold uppercase transition-all bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-500 hover:text-indigo-600 shadow-sm disabled:opacity-50">
                    <SparklesIcon className={`w-3.5 h-3.5 ${isAiLoading ? 'animate-spin' : ''}`} />
                    <span>Auto-Detectar</span>
                </button>

                <button onClick={onSimulate} className="flex items-center gap-2 px-5 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl text-[10px] font-bold uppercase shadow-lg shadow-indigo-500/20 transition-all active:scale-95">
                    <PlayCircleIcon className="w-4 h-4" />
