import { GoogleGenAI, Type } from "@google/genai";
import { Transaction } from '../types';
import { Logger } from "./monitoringService";

const getAIClient = () => {
    if (!process.env.API_KEY) throw new Error("Chave de API do Gemini não configurada.");
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

const safeJsonParse = (input: any, fallback: any = []) => {
    if (!input) return fallback;
    let sanitized = String(input).trim();
    sanitized = sanitized.replace(/^```json\s*/g, '').replace(/\s*```$/g, '');

    try {
        const parsed = JSON.parse(sanitized);
        return parsed.rows || parsed.transactions || (Array.isArray(parsed) ? parsed : fallback);
    } catch (e) {
        const arrayMatch = sanitized.match(/\[\s*\{.*\}\s*\]/s);
        if (arrayMatch) {
            try { return JSON.parse(arrayMatch[0]); } catch (inner) {}
        }
        return fallback;
    }
};

async function callWithSimpleRetry(fn: () => Promise<any>, retries = 2): Promise<any> {
    try {
        return await fn();
    } catch (error: any) {
        if (retries > 0) {
            await new Promise(r => setTimeout(r, 2000));
            return callWithSimpleRetry(fn, retries - 1);
        }
        throw error;
    }
};

/**
 * MOTOR DE EXTRAÇÃO POR CONTRATO (V26 - FOCO EM FIDELIDADE TEXTUAL)
 */
export const extractTransactionsWithModel = async (rawText: string, modelContext?: string): Promise<any> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();

        const finalPrompt = `VOCÊ É UM EXECUTOR DE MODELO APRENDIDO.
            NÃO USE REGRAS PRÓPRIAS. NÃO TENTE ADIVINHAR.

            SUA ÚNICA FONTE DE VERDADE É O EXEMPLO ABAIXO:
            ${modelContext ? `\n--- EXEMPLO DE TREINO (CONTRATO) ---\n${modelContext}\n` : ''}

            INSTRUÇÕES CRÍTICAS:
            1. Observe como as descrições no EXEMPLO DE TREINO foram limpas.
            2. Se o exemplo removeu nomes de bancos, termos como 'PIX', 'TED', ou códigos, você DEVE fazer exatamente o mesmo.
            3. O texto resultante na propriedade 'description' deve ser idêntico ao padrão visual ensinado.

            Retorne apenas JSON seguindo o esquema.

            TEXTO PARA PROCESSAR AGORA:
            ${rawText}`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: finalPrompt,
            config: {
                temperature: 0,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        rows: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    date: { type: Type.STRING },
                                    description: { type: Type.STRING },
                                    amount: { type: Type.NUMBER },
                                    type: { type: Type.STRING },
                                    paymentMethod: { type: Type.STRING }
                                },
                                required: ["date", "description", "amount"]
                            }
                        }
                    },
                    required: ["rows"]
                }
            }
        });
        return safeJsonParse(response.text);
    });
};

