            const numAmount = parseFloat(stdAmount);

            if (isoDate && !isNaN(numAmount)) {
                rawResults.push({
                    id: `hyb-${model.id}-${idx}-${Date.now()}`,
                    date: isoDate,
                    description: rawDesc.trim(), // Texto bruto da coluna
                    rawDescription: line,
                    amount: numAmount,
                    originalAmount: rawAmount,
                    cleanedDescription: rawDesc.trim(),
                    contributionType: TypeResolver.resolveFromDescription(rawDesc),
                    paymentMethod: mapping.paymentMethodColumnIndex !== undefined && cells[mapping.paymentMethodColumnIndex] 
                        ? cells[mapping.paymentMethodColumnIndex] 
                        : TypeResolver.resolveFromDescription(rawDesc)
                });
            }
        });

        if (rawResults.length === 0) return [];

        // 2️⃣ LIMPEZA INTELIGENTE (IA EM LOTE ÚNICO DE DESCRIÇÕES ÚNICAS)
        // Reduzimos 750 descrições para talvez 50 únicas, tornando o processo 15x mais rápido.
        const uniqueDescriptions = Array.from(new Set(rawResults.map(r => r.description)));

        try {
            console.log(`[ContractExecutor] Limpando ${uniqueDescriptions.length} descrições únicas via IA...`);

            const trainingSnippet = model.snippet || "";
            const cleanedMap = await cleanDescriptionsInBatch(uniqueDescriptions, trainingSnippet);

            // 3️⃣ APLICAÇÃO DOS RESULTADOS LIMPOS
            return rawResults.map(res => ({
                ...res,
                description: cleanedMap[res.description] || res.description,
                cleanedDescription: cleanedMap[res.description] || res.description
            }));

        } catch (error) {
            console.error("[ContractExecutor] Falha na limpeza IA, mantendo nomes brutos.", error);
            return rawResults;
        }
    }
};

