/**
 * 📜 CONTRACT EXECUTOR (V40 - VELOCIDADE COM FIDELIDADE)
 */
export const ContractExecutor = {
    async apply(model: FileModel, adaptedInput: any, globalKeywords: string[] = []): Promise<Transaction[]> {
        if (!model || !model.mapping) return [];

        const rawText = adaptedInput?.__rawText || (typeof adaptedInput === 'string' ? adaptedInput : "");
        if (!rawText.trim()) return [];

        const { mapping } = model;
        const lines = rawText.split(/\r?\n/).filter(l => l.trim().length > 0);

        // 🧠 EXTRAÇÃO VIA IA (MODO BLOCO OU COLUNAS TREINADAS)
        // Usamos a IA para garantir que a limpeza de nomes (ex: remover RECEBIMENTO PIX) 
        // seja feita exatamente como o usuário ensinou no snippet de treino.

        const trainingContext = `### CONTRATO DE EXTRAÇÃO (SIGA RIGOROSAMENTE):\n${model.snippet?.substring(0, 4000)}\n\nIMPORTANTE: Se o exemplo acima remove 'RECEBIMENTO PIX' ou simplifica nomes, você DEVE fazer o mesmo na saída JSON.`;

        // Lotes grandes de 250 linhas para minimizar chamadas e maximizar velocidade.
        const LINES_PER_BATCH = 250;
        const batches: string[] = [];
        for (let i = 0; i < lines.length; i += LINES_PER_BATCH) {
            batches.push(lines.slice(i, i + LINES_PER_BATCH).join('\n'));
        }

        console.log(`[ContractExecutor] Processando ${lines.length} linhas em ${batches.length} lotes paralelos...`);

        const batchPromises = batches.map(async (batchText, batchIdx) => {
            try {
                const aiResult = await extractTransactionsWithModel(batchText, trainingContext);
                if (aiResult && aiResult.length > 0) {
                    return aiResult.map((tx: any, idx: number) => ({
                        id: `exec-v40-${model.id}-${batchIdx}-${idx}-${Date.now()}`,
                        date: tx.date,
                        description: tx.description, // Respeita a limpeza da IA
                        rawDescription: tx.description,
                        amount: tx.amount,
                        originalAmount: String(tx.amount),
                        cleanedDescription: tx.description,
                        contributionType: tx.type || 'AUTO',
                        paymentMethod: tx.paymentMethod || 'OUTROS'
                    }));
                }
                return [];
            } catch (e) {
                console.error(`[ContractExecutor] Falha no lote ${batchIdx}:`, e);
                return [];
            }
        });

        const resultsArray = await Promise.all(batchPromises);
        const finalResults = resultsArray.flat();

        console.log(`[ContractExecutor] Extração concluída: ${finalResults.length} registros.`);
        return finalResults;
    }
};

